import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { getAllDoctors, deleteDoctor, addReview, getReviews } from '../services/api';
import { useAuth } from '../context/AuthContext';
import Navbar from '../components/Navbar';

const SPECS = ['All', 'Cardiology', 'Neurology', 'Orthopedics', 'Dermatology', 'Pediatrics', 'General Medicine'];

const specColors = {
  Cardiology: { bg: '#fef2f2', color: '#dc2626', icon: '🫀' },
  Neurology: { bg: '#f0fdf4', color: '#16a34a', icon: '🧠' },
  Orthopedics: { bg: '#fff7ed', color: '#ea580c', icon: '🦴' },
  Dermatology: { bg: '#fdf4ff', color: '#a21caf', icon: '✨' },
  Pediatrics: { bg: '#eff6ff', color: '#2563eb', icon: '👶' },
  'General Medicine': { bg: '#f0fdfa', color: '#0d9488', icon: '🩺' },
};

const Doctors = () => {
  const { user } = useAuth();
  const navigate = useNavigate();

  const [doctors, setDoctors] = useState([]);
  const [search, setSearch] = useState('');
  const [specFilter, setSpecFilter] = useState('All');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getAllDoctors()
      .then(res => setDoctors(res.data))
      .catch(console.log)
      .finally(() => setLoading(false));
  }, []);

  const handleDelete = async (id) => {
    if (!window.confirm('Delete doctor?')) return;
    await deleteDoctor(id);
    setDoctors(doctors.filter(d => d._id !== id));
  };

  const filtered = doctors.filter(d => {
    const name = d.userId?.name?.toLowerCase() || '';
    const spec = d.specialization?.toLowerCase() || '';
    const q = search.toLowerCase();

    return (specFilter === 'All' || d.specialization === specFilter) &&
           (!q || name.includes(q) || spec.includes(q));
  });

  return (
    <div style={S.page}>
      <Navbar />

      <div style={S.wrap}>
        <h1>Doctors</h1>

        <input
          placeholder="Search..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          style={S.input}
        />

        <div style={S.filters}>
          {SPECS.map(s => (
            <button key={s}
              style={{ ...S.pill, ...(specFilter === s ? S.activePill : {}) }}
              onClick={() => setSpecFilter(s)}>
              {s}
            </button>
          ))}
        </div>

        {loading ? <p>Loading...</p> : (
          <div style={S.grid}>
            {filtered.map(d => {
              const sc = specColors[d.specialization] || specColors['General Medicine'];

              return (
                <div key={d._id} style={S.card}>
                  <h3>{d.userId?.name}</h3>
                  <p>{d.specialization}</p>
                  <p>⭐ {d.rating}</p>
                  <p>₹{d.consultationFee}</p>

                  {user?.role === 'patient' && (
                    <button onClick={() => navigate('/book')}>
                      Book
                    </button>
                  )}

                  {user?.role === 'admin' && (
                    <button onClick={() => handleDelete(d._id)}>
                      Delete
                    </button>
                  )}

                  {/* ⭐ REVIEW FEATURE */}
                  <ReviewForm doctorId={d._id} userId={user?._id} />
                  <ReviewList doctorId={d._id} />
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

//////////////////////////////////////////////////
// ⭐ REVIEW FORM
//////////////////////////////////////////////////
const ReviewForm = ({ doctorId, userId }) => {
  const [rating, setRating] = useState(0);
  const [comment, setComment] = useState('');

  const submit = async () => {
    if (!rating) return alert("Select rating");

    await addReview({ doctorId, rating, comment, userId });

    alert("Review added!");
    setRating(0);
    setComment('');
  };

  return (
    <div style={{ marginTop: 10 }}>
      <h4>Add Review</h4>

      {[1,2,3,4,5].map(s => (
        <span key={s}
          onClick={() => setRating(s)}
          style={{
            cursor: 'pointer',
            color: s <= rating ? 'gold' : 'gray',
            fontSize: 20
          }}>
          ★
        </span>
      ))}

      <textarea
        placeholder="Write review"
        value={comment}
        onChange={(e) => setComment(e.target.value)}
        style={{ width: '100%' }}
      />

      <button onClick={submit}>Submit</button>
    </div>
  );
};

//////////////////////////////////////////////////
// 📋 REVIEW LIST
//////////////////////////////////////////////////
const ReviewList = ({ doctorId }) => {
  const [reviews, setReviews] = useState([]);

  useEffect(() => {
    getReviews(doctorId).then(res => setReviews(res.data));
  }, [doctorId]);

  return (
    <div style={{ marginTop: 10 }}>
      <h4>Reviews</h4>

      {reviews.map(r => (
        <div key={r._id}>
          <b>{r.userId?.name}</b>
          <div>{"★".repeat(r.rating)}</div>
          <p>{r.comment}</p>
        </div>
      ))}
    </div>
  );
};

//////////////////////////////////////////////////
// 🎨 STYLES
//////////////////////////////////////////////////
const S = {
  page: { padding: 20 },
  wrap: { maxWidth: 1000, margin: 'auto' },
  input: { width: '100%', padding: 10, marginBottom: 10 },
  filters: { marginBottom: 10 },
  pill: { marginRight: 5, padding: 5 },
  activePill: { background: '#6366f1', color: '#fff' },
  grid: { display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 20 },
  card: { border: '1px solid #ddd', padding: 10 }
};

export default Doctors;
